 static void TrainModel(string csvPath, string modelPath)
 {
     var mlContext = new MLContext(seed: 42);
     mlContext.ComponentCatalog.RegisterAssembly(typeof(ChurnMappingFactory).Assembly);

     var data = mlContext.Data.LoadFromTextFile<CustomerInput>(
         csvPath, hasHeader: true, separatorChar: ',');

     var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

     var pipeline = mlContext.Transforms.CustomMapping<CustomerInput, ChurnLabel>(
             (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
             contractName: "ChurnMapping")
         .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerInput.Region)))
         .Append(mlContext.Transforms.Concatenate("Features",
             nameof(CustomerInput.Age),
             nameof(CustomerInput.Income),
             "RegionEncoded",
             nameof(CustomerInput.PurchaseHistory)))
         .Append(mlContext.Transforms.NormalizeMinMax("Features"))
         .Append(mlContext.BinaryClassification.Trainers.FastTree(
             labelColumnName: "Label",
             featureColumnName: "Features"));

     var model = pipeline.Fit(split.TrainSet);

     // Evaluate on test set (may fail with very small datasets)
     try
     {
         var predictions = model.Transform(split.TestSet);
         var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
         Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
     }
     catch (ArgumentOutOfRangeException)
     {
         Console.WriteLine("Model trained — evaluation skipped (dataset too small for meaningful test split).");
     }

     mlContext.Model.Save(model, data.Schema, modelPath);
 }

